function normalize(s: string): string {
  return s.normalize('NFKD').replace(/[\u0300-\u036f]/g, '').toLowerCase().replace(/[^a-z0-9]+/g, '')
}

export function getPlaceClimate(countryCode: string, placeName: string): PlaceClimateEntry | undefined {
  return placesClimate[countryCode]?.[normalize(placeName)]
}
